import{_ as s,o as e,c as a,a3 as l}from"./chunks/framework.CS9vaShW.js";const k=JSON.parse('{"title":"/blog 博客操作流程规范","description":"","frontmatter":{},"headers":[],"relativePath":"public/prompt/博客/博客创建流程.md","filePath":"public/prompt/博客/博客创建流程.md","lastUpdated":1784075578000}'),n={name:"public/prompt/博客/博客创建流程.md"};function t(o,i,r,p,d,c){return e(),a("div",null,[...i[0]||(i[0]=[l(`<h1 id="blog-博客操作流程规范" tabindex="-1"><code>/blog</code> 博客操作流程规范 <a class="header-anchor" href="#blog-博客操作流程规范" aria-label="Permalink to &quot;\`/blog\` 博客操作流程规范&quot;">​</a></h1><p>本规范定义 <code>/blog</code> 命令的完整执行流程，包括命令解析、文章内容规划、指导文档读取、文件放置、GitHub 仓库写入、commit 与 push 规则。</p><p>文章的具体写作风格、内容深度、结构范式、案例使用和领域约束，必须由对应写作指导文档决定。本规范只定义操作流程和安全边界。</p><p>执行 <code>/blog</code> 时，必须按以下顺序处理：</p><ol><li>解析命令，确定模式</li><li>确定文章结构和内容</li><li>确定 GitHub 操作方式</li><li>写入文章文件</li><li>创建 commit 并 push 到远端分支</li><li>总结并返回执行结果</li></ol><p>任何关键步骤失败时，必须立即停止执行，不得继续写入、提交或推送。</p><h1 id="_1-解析命令-确定模式" tabindex="-1">1. 解析命令，确定模式 <a class="header-anchor" href="#_1-解析命令-确定模式" aria-label="Permalink to &quot;1. 解析命令，确定模式&quot;">​</a></h1><h2 id="_1-1-判断执行模式" tabindex="-1">1.1 判断执行模式 <a class="header-anchor" href="#_1-1-判断执行模式" aria-label="Permalink to &quot;1.1 判断执行模式&quot;">​</a></h2><p><code>/blog</code> 支持两种模式：新建文章模式、修改已有文章模式。</p><h3 id="_1-1-1-新建文章模式" tabindex="-1">1.1.1 新建文章模式 <a class="header-anchor" href="#_1-1-1-新建文章模式" aria-label="Permalink to &quot;1.1.1 新建文章模式&quot;">​</a></h3><p>当命令中不包含 <code>--page</code> 时，必须进入新建文章模式。</p><p>命令格式：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/blog</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --title</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 标题</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 标签1,标签2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --category</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 分类</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --description</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 描述</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>新建文章时，如果没有指定 <code>title</code>、<code>tag</code>、<code>category</code> 或 <code>description</code>，必须根据内容自动生成。</p><h3 id="_1-1-2-修改已有文章模式" tabindex="-1">1.1.2 修改已有文章模式 <a class="header-anchor" href="#_1-1-2-修改已有文章模式" aria-label="Permalink to &quot;1.1.2 修改已有文章模式&quot;">​</a></h3><p>只要命令中包含 <code>--page</code>，必须进入修改已有文章模式。</p><p>命令格式：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/blog</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --page</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> some-page.md</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/blog</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --page</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> some-page.md</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --description</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 描述</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果命令中包含 <code>title</code>、<code>tag</code>、<code>category</code> 或 <code>description</code> 中任一参数，必须视为对已有文章元信息进行修改。</p><h2 id="_1-2-参数规则" tabindex="-1">1.2 参数规则 <a class="header-anchor" href="#_1-2-参数规则" aria-label="Permalink to &quot;1.2 参数规则&quot;">​</a></h2><ol><li>参数解析失败时，必须停止执行，并说明失败原因。</li><li>修改文章时，必须确认仓库中该文件存在。</li><li><code>--description</code> 用于指定 Frontmatter 的 <code>description</code> 字段。</li><li>如果没有提供 <code>--description</code>，必须根据文章内容自动生成 <code>description</code>。</li><li><code>description</code> 内容应概括文章主题、核心问题和主要分析方向，长度约 50 个中文字符。</li><li><code>description</code> 必须是 1 段纯文本，不得包含 Markdown 图片、HTML 标签、表格、代码块或链接标记。</li></ol><h1 id="_2-确定文章结构与内容" tabindex="-1">2. 确定文章结构与内容 <a class="header-anchor" href="#_2-确定文章结构与内容" aria-label="Permalink to &quot;2. 确定文章结构与内容&quot;">​</a></h1><h2 id="_2-1-vitepress-markdown-文档-frontmatter-结构" tabindex="-1">2.1 VitePress Markdown 文档 Frontmatter 结构 <a class="header-anchor" href="#_2-1-vitepress-markdown-文档-frontmatter-结构" aria-label="Permalink to &quot;2.1 VitePress Markdown 文档 Frontmatter 结构&quot;">​</a></h2><p>Frontmatter 必须使用以下结构：</p><div class="language-md vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">title</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">文章标题</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">category</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">分类</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tags</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">标签1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">标签2</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">date</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">YYYY-MM-DD</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">一段简短的文章描述</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{{博客具体内容}}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>Frontmatter 规则：</p><ol><li><code>title</code>、<code>category</code>、<code>tags</code>、<code>description</code> 必须存在，并参考上一步确定的内容。</li><li>新建文章时，<code>date</code> 必须使用当前日期。</li><li>新建文章时，必须始终填写 <code>description</code> 字段，不依赖也不主动填写 <code>excerpt</code> 字段；如果命令提供了 <code>--description</code>，必须使用用户提供的描述，否则必须根据文章内容自动生成。</li><li>修改文章时，如果命令显式提供 <code>--description</code>，必须更新 <code>description</code> 字段；如果未提供但原文章缺少 <code>description</code>，必须根据文章内容自动补齐；如果原文章已有 <code>description</code> 且用户未要求修改，必须保持不变。</li><li><code>description</code> 用于 VitePress 首页文章列表展示，必须是 1 段纯文本短描述，不得包含 Markdown 图片、HTML 标签、表格、代码块或链接标记。</li><li><code>description</code> 应概括文章主题、核心问题和主要分析方向，长度约 50 个中文字符，避免过长，优先控制在 80 字以内。</li><li>不得添加当前博客系统不支持的 Frontmatter 字段，除非原文已有或用户明确要求。</li><li>修改文章时，应尽量保持原 Frontmatter 字段顺序和未涉及字段不变。</li><li>修改文章时，除非显式重新指定，未指定的字段不得主动修改；但 <code>description</code> 缺失时必须自动补齐。</li></ol><h2 id="_2-2-博客内容" tabindex="-1">2.2 博客内容 <a class="header-anchor" href="#_2-2-博客内容" aria-label="Permalink to &quot;2.2 博客内容&quot;">​</a></h2><ol><li>必须根据上下文确定博客类型，并从以下模板类型中选择一个或多个规范。</li><li>必须读取 GitHub 上的规范文件，并按规范文件组织博客内容结构。</li></ol><ul><li>技术类博客：<code>https://raw.githubusercontent.com/xunserver/xunserver.github.io/refs/heads/main/prompt/博客/文章模板/技术.md</code></li><li>金融类博客：<code>https://raw.githubusercontent.com/xunserver/xunserver.github.io/refs/heads/main/prompt/博客/文章模板/金融.md</code></li><li>杂项类博客：<code>https://raw.githubusercontent.com/xunserver/xunserver.github.io/refs/heads/main/prompt/博客/文章模板/金融.md</code></li><li>每日总结博客：<code>https://raw.githubusercontent.com/xunserver/xunserver.github.io/refs/heads/main/prompt/博客/文章模板/每日总结.md</code></li><li>量化交易系统架构类博客：<code>https://raw.githubusercontent.com/xunserver/xunserver.github.io/refs/heads/main/prompt/博客/文章模板/量化交易系统架构.md</code></li></ul><p>不确定风格时，必须使用杂项类博客，按随性记录处理。</p><ol start="3"><li>必须根据当前聊天内容组织博客内容。</li><li>必须结合上方规范文件的结构，生成最终博客内容。</li></ol><h1 id="_3-仓库与分支规则" tabindex="-1">3. 仓库与分支规则 <a class="header-anchor" href="#_3-仓库与分支规则" aria-label="Permalink to &quot;3. 仓库与分支规则&quot;">​</a></h1><p>博客文章必须通过 GitHub blog 仓库创建或更新。必须使用当前上下文提供的 GitHub 操作工具。</p><p>执行规则：</p><ol><li>仅允许在 <code>main</code> 分支操作。</li><li>commit message 必须使用以下格式： <ul><li><code>post: 新增 xxxx 文章</code></li><li><code>post: 更新 xxx文章</code></li></ul></li><li>不得仅在本地或临时环境中生成文章后结束。</li><li>成功执行的最终结果必须写入 GitHub 仓库。</li><li>commit 成功后，必须 push 到远端分支。</li><li>未成功 push 时，不得宣称博客已创建或已更新。</li><li>不得强制推送。</li><li>Markdown 文章必须按照 VitePress 规则放到 <code>posts/{slug}.md</code> 中。</li><li>文章图片、附件和其他静态资源只能放到 <code>public/posts/&lt;slug&gt;/</code> 目录中。都是放在原始 blog的仓库中，不是放在部署后仓库中</li><li>仅允许操作文章相关内容。</li><li>禁止改动任何其他代码。</li><li>只能修改 <code>posts</code> 目录和 <code>public</code> 目录下的内容。</li></ol><h2 id="_3-1-slug-生成规则" tabindex="-1">3.1 Slug 生成规则 <a class="header-anchor" href="#_3-1-slug-生成规则" aria-label="Permalink to &quot;3.1 Slug 生成规则&quot;">​</a></h2><p>新建文章时，必须根据标题生成 slug。</p><p>Slug 规则：</p><ol><li>尽量短、稳定、可读。</li><li>由小写英文和空格组成。</li><li>无法生成 slug 时，使用 <code>post-YYYYMMDD-HHMM</code>。</li><li>如果 <code>posts/&lt;slug&gt;.md</code> 已存在，必须停止执行，并提示用户手动输入一个 slug。</li></ol><h1 id="_4-成功返回信息" tabindex="-1">4. 成功返回信息 <a class="header-anchor" href="#_4-成功返回信息" aria-label="Permalink to &quot;4. 成功返回信息&quot;">​</a></h1><p>成功执行后，必须返回以下信息：</p><ul><li>执行模式：新建文章或修改文章。</li><li>文章路径。</li><li>资源目录路径。</li><li>标题。</li><li>分类。</li><li>标签。</li><li>描述。</li><li>commit message。</li><li>推送分支。</li><li>GitHub 文件链接或仓库路径。</li><li>是否已成功 push。</li></ul><h1 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h1><ul><li>xunserver/blog 是源码仓库，所有文章.md和图片资源等是放在这个仓库中。xunserver/xunserver.github.io 是vitepress 构建部署后仓库，是通过workflow/deploy 部署的，读取prompt等公开的文件是通过这个仓库暴露出的raw文件地址来实现。务必不能搞混</li><li>从公开仓库 xunserver/xunserver.github.io 读取流程文件</li><li>从公开仓库 xunserver/xunserver.github.io 读取文章模板</li></ul>`,45)])])}const u=s(n,[["render",t]]);export{k as __pageData,u as default};
